111→    private var readerTagsList = ReaderTagList()
112→
113→    init {
114→        EventBus.getDefault().register(this)
115→    }
116→
117→    fun start() {
118→        if (tagsRequireUpdate()) _updateTags.value = Event(Unit)
119→        if (initialized) return
120→        loadTabs()
121→        if (jetpackBrandingUtils.shouldShowJetpackPoweredBottomSheet()) showJetpackPoweredBottomSheet()
122→    }
