173→    private fun tagsRequireUpdate(): Boolean {
174→        val lastUpdated = appPrefsWrapper.readerTagsUpdatedTimestamp
175→        val now = dateProvider.getCurrentDate().time
176→        return now - lastUpdated > UPDATE_TAGS_THRESHOLD
177→    }
