179→    fun updateSelectedContent(selectedTag: ReaderTag) {
180→        getMenuItemFromReaderTag(selectedTag)?.let { newSelectedMenuItem ->
181→            // Update top bar UI state so menu is updated with new selected item
182→            _topBarUiState.value?.let {
183→                _topBarUiState.value = it.copy(
184→                    selectedItem = newSelectedMenuItem,
185→                    filterUiState = null,
186→                )
187→            }
188→            // Updated post list content
189→            val currentUiState = _uiState.value as? ContentUiState
190→            currentUiState?.let {
191→                _uiState.value = currentUiState.copy(
192→                    selectedReaderTag = selectedReaderTag()
193→                )
194→            }
195→        }
196→    }
