214→    fun onSettingsActionClicked() {
215→        if (isSettingsSupported()) {
216→            completeQuickStartFollowSiteTaskIfNeeded()
217→            _showSettings.value = Event(Unit)
218→        } else if (BuildConfig.DEBUG) {
219→            throw IllegalStateException("Settings should be hidden when isSettingsSupported returns false.")
220→        }
221→    }
222→
223→    @Suppress("unused", "UNUSED_PARAMETER")
224→    @Subscribe(threadMode = MAIN)
225→    fun onTagsUpdated(event: ReaderEvents.FollowedTagsChanged) {
226→        loadTabs()
227→    }
